class Solution(object):
    def semiOrderedPermutation(self, nums):
        n = len(nums)
        pos1 = nums.index(1)
        posn = nums.index(n)
        cost = pos1 + (n - 1 - posn)
        if pos1 > posn:
            cost -= 1
        return cost
